1→// Core type definitions for Carlo Baclao Portfolio Website
2→
3→export type NavigationSection = 'home' | 'about' | 'skills' | 'experience' | 'projects' | 'github' | 'contact';
4→
5→export interface NavigationContextType {
6→  currentSection: NavigationSection;
7→  setCurrentSection: (section: NavigationSection) => void;
8→  isResumeOpen: boolean;
9→  openResume: () => void;
10→  closeResume: () => void;
11→  selectedCertification: CertificationItem | null;
12→  isCertModalOpen: boolean;
13→  openCertModal: (cert: CertificationItem) => void;
14→  closeCertModal: () => void;
15→}
16→
17→export interface NavigationState {
