1→'use client';
2→
3→import { useEffect, useRef } from 'react';
4→import { motion, AnimatePresence } from 'framer-motion';
5→import { CertificationItem } from '@/types';
6→import { X, Award, Building2, Calendar, ExternalLink } from 'lucide-react';
7→import Image from 'next/image';
8→
9→interface CertificationModalProps {
10→  isOpen: boolean;
11→  onClose: () => void;
12→  certification: CertificationItem | null;
13→}
14→
15→export function CertificationModal({ isOpen, onClose, certification }: CertificationModalProps) {
16→  const modalRef = useRef<HTMLDivElement>(null);
17→  const closeButtonRef = useRef<HTMLButtonElement>(null);
18→
19→  useEffect(() => {
20→    const handleEscape = (event: KeyboardEvent) => {
21→      if (event.key === 'Escape' && isOpen) {
22→        onClose();
23→      }
24→    };
25→
26→    if (isOpen) {
27→      document.addEventListener('keydown', handleEscape);
28→      closeButtonRef.current?.focus();
29→      document.body.style.overflow = 'hidden';
30→    }
31→
32→    return () => {
33→      document.removeEventListener('keydown', handleEscape);
34→      document.body.style.overflow = 'unset';
35→    };
36→  }, [isOpen, onClose]);
37→
38→  const handleBackdropClick = (event: React.MouseEvent) => {
39→    if (event.target === event.currentTarget) {
40→      onClose();
41→    }
42→  };
43→
44→  if (!certification) return null;
45→
46→  return (
47→    <AnimatePresence>
48→      {isOpen && (
49→        <motion.div
50→          className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6"
51→          onClick={handleBackdropClick}
52→          role="dialog"
53→          aria-modal="true"
54→          aria-labelledby="cert-modal-title"
55→          initial={{ opacity: 0 }}
56→          animate={{ opacity: 1 }}
57→          exit={{ opacity: 0 }}
58→          transition={{ duration: 0.3 }}
59→        >
60→          <motion.div
61→            className="absolute inset-0 bg-black/60"
62→            initial={{ opacity: 0 }}
63→            animate={{ opacity: 1 }}
64→            exit={{ opacity: 0 }}
65→          />
66→
67→          <motion.div
68→            ref={modalRef}
69→            className="relative bg-white dark:bg-slate-800 rounded-2xl shadow-xl max-w-lg w-full mx-4 max-h-[90vh] overflow-hidden border border-gray-200 dark:border-slate-700"
70→            initial={{ opacity: 0, scale: 0.9, y: 20 }}
71→            animate={{ opacity: 1, scale: 1, y: 0 }}
72→            exit={{ opacity: 0, scale: 0.95, y: 10 }}
73→            transition={{ type: 'spring', stiffness: 300, damping: 25 }}
74→          >
75→            <div className="flex items-center justify-between p-5 border-b border-gray-200 dark:border-slate-700">
76→              <div className="flex items-center gap-3 min-w-0">
77→                <div className="w-10 h-10 rounded-full bg-orange-900/30 text-orange-400 flex items-center justify-center shrink-0">
78→                  <Award size={20} />
79→                </div>
80→                <div className="min-w-0">
81→                  <h2 id="cert-modal-title" className="text-lg font-semibold text-gray-900 dark:text-white truncate">Certification</h2>
82→                  <p className="text-xs text-gray-500 dark:text-gray-400">Credential Details</p>
83→                </div>
84→              </div>
85→              <motion.button
86→                ref={closeButtonRef}
87→                onClick={onClose}
88→                className="p-2 text-gray-500 dark:text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 hover:bg-gray-100 dark:hover:bg-slate-700 rounded-lg transition-colors duration-200 focus:outline-none focus:ring-2 focus:ring-gray-900 focus:ring-offset-2"
89→                aria-label="Close certification modal"
90→                whileHover={{ scale: 1.1, rotate: 90 }}
91→                whileTap={{ scale: 0.9 }}
92→                initial={{ opacity: 0, rotate: -90 }}
93→                animate={{ opacity: 1, rotate: 0 }}
94→                transition={{ delay: 0.2 }}
95→              >
96→                <X size={20} />
97→              </motion.button>
98→            </div>
99→
100→            <div className="p-5 overflow-y-auto max-h-[calc(90vh-80px)]">
101→              {certification.imageUrl && (
102→                <motion.div
103→                  className="mb-5 rounded-xl overflow-hidden border border-slate-700 bg-slate-700/50"
104→                  initial={{ opacity: 0, y: 10 }}
105→                  animate={{ opacity: 1, y: 0 }}
106→                  transition={{ delay: 0.1 }}
107→                >
108→                  <div className="relative w-full" style={{ aspectRatio: '16/10' }}>
109→                    <Image
